import React, { useEffect, useRef } from 'react';

function ChatWindow({ messages, input, setInput, onSend, theme, sidebarOpen }) {
  const bottomRef = useRef(null);

  // 新消息时自动滚动到底部
  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleKeyDown = (e) => {
    if (e.key === 'Enter') {
      if (e.shiftKey) {
        // 换行
        return;
      }
      e.preventDefault();
      onSend();
    }
  };

  return (
    <div className="flex-1 flex flex-col min-w-0 bg-white/30 backdrop-blur-sm">
      {/* 消息列表 */}
      <div className="flex-1 overflow-y-auto px-4 py-6 space-y-4">
        {messages.length === 0 && (
          <div className="text-center text-gray-400 mt-20">
            <div className="text-5xl mb-4">🐣</div>
            <p className="text-lg font-semibold">哎呀，还没有对话~</p>
            <p className="text-sm">试试输入“生成5道小数乘法作业”，小智老师马上帮助你！</p>
          </div>
        )}
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[80%] px-4 py-3 rounded-3xl bubble-enter ${
              msg.sender === 'user'
                ? theme.userBubble + ' rounded-br-lg'
                : msg.text === 'loading'
                  ? 'bg-white/80 border border-gray-200 text-gray-400 rounded-bl-lg'
                  : theme.aiBubble + ' rounded-bl-lg'
            } ${theme.shadow}`}>
              {msg.text === 'loading' ? (
                <div className="flex items-center gap-2">
                  <span className="text-sm">小智老师正在思考</span>
                  <div className="dot-pulse flex gap-1">
                    <span className="w-1.5 h-1.5 bg-gray-400 rounded-full"></span>
                    <span className="w-1.5 h-1.5 bg-gray-400 rounded-full"></span>
                    <span className="w-1.5 h-1.5 bg-gray-400 rounded-full"></span>
                  </div>
                </div>
              ) : (
                <p className="text-sm leading-relaxed whitespace-pre-wrap">{msg.text}</p>
              )}
            </div>
          </div>
        ))}
        <div ref={bottomRef} />
      </div>

      {/* 输入区 */}
      <div className="p-4 bg-white/70 backdrop-blur-md border-t border-gray-100">
        <div className="flex gap-2 max-w-4xl mx-auto">
          <textarea
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="✨ 输入问题，小智老师帮你解答…"
            rows={1}
            className={`flex-1 resize-none rounded-2xl border ${theme.input} bg-white/60 px-4 py-3 text-sm focus:outline-none focus:ring-2 transition`}
          />
          <button
            onClick={onSend}
            className={`px-6 rounded-2xl font-semibold text-sm ${theme.sendBtn} transition-all duration-200 hover:scale-105`}
          >
            发送 ↑
          </button>
        </div>
        <p className="text-xs text-gray-400 mt-1 ml-2">回车发送 · Shift+回车换行</p>
      </div>
    </div>
  );
}

export default ChatWindow;
